/*
    isOddEvenGen(thirdPersonPronoun: string) => () => boolean

  The function returned by this generator returns true if it's been called
  an odd number of times, and false if it's been called an even number of
  times.

    Usage:

  var isOdd = isOddEvenGen();
  console.log(isOdd.next().value); // prints true
  console.log(isOdd.next().value); // prints false
  console.log(isOdd.next().value); // prints true again

    or

  var isOdd = isOddEvenGen("She");
  console.log(isOdd.next().value); // prints true, and "She loves me!"
  console.log(isOdd.next().value); // prints false, and "She loves me not!"
*/
function* isOddEvenGen(thirdPersonPronoun=undefined){
  const not = -1;
  var lovesme = 1;

  while(true){
    yield thirdPersonPronoun === undefined ? lovesme > 0 : `${thirdPersonPronoun} loves me${lovesme > 0 ? "" : " not"}!`;
    lovesme = lovesme * not;
  }
}

var isOdd = isOddEvenGen();

console.log(isOdd.next().value);
console.log(isOdd.next().value);
console.log(isOdd.next().value);

var isOdd = isOddEvenGen("She");

console.log(isOdd.next().value);
console.log(isOdd.next().value);
console.log(isOdd.next().value);
